insert into earth_pulse.metrics (id,name,unit,domain,source,source_url,licence,explainer,time_resolution,first_year,last_year) values ('co2','CO2 emissions','Mt CO2/year','climate','Global Carbon Budget via Our World in Data','https://ourworldindata.org/co2-emissions','CC BY 4.0','Carbon dioxide released each year from burning fossil fuels and industry. The main driver of global warming.','annual',1750,2024),('co2_per_capita','CO2 emissions per person','t CO2/person/year','climate','Global Carbon Budget via Our World in Data','https://ourworldindata.org/co2-emissions','CC BY 4.0','Each person''s share of their country''s yearly CO2 emissions. A fairer way to compare countries of very different sizes.','annual',1750,2024),('temperature_anomaly','Temperature anomaly','°C vs 1991-2020','climate','Copernicus Climate Change Service (ERA5) via Our World in Data','https://ourworldindata.org/grapher/annual-temperature-anomalies','CC BY 4.0','How much warmer or cooler a country''s year was compared with its 1991-2020 average. Watch the map turn red as you move the slider towards today.','annual',1940,2025),('renewables_share_energy','Renewable energy share','% of primary energy','energy','Energy Institute Statistical Review via Our World in Data','https://ourworldindata.org/renewable-energy','CC BY 4.0','The slice of a country''s energy that comes from renewables such as wind, solar and hydro.','annual',1965,2024),('fossil_share_energy','Fossil fuel share','% of primary energy','energy','Energy Institute Statistical Review via Our World in Data','https://ourworldindata.org/fossil-fuels','CC BY 4.0','The slice of a country''s energy still coming from coal, oil and gas. The number the world is trying to shrink.','annual',1965,2024),('energy_per_capita','Energy use per person','kWh/person/year','energy','Energy Institute / Ember via Our World in Data','https://ourworldindata.org/energy-production-consumption','CC BY 4.0','How much energy each person uses in a year, across electricity, transport, heating and industry.','annual',1965,2024),('pm25','Air pollution (PM2.5)','µg/m³ annual mean','pollution','World Bank / van Donkelaar et al. via Our World in Data','https://ourworldindata.org/air-pollution','CC BY 4.0','Average exposure to fine particles small enough to enter the bloodstream. The WHO guideline is 5 µg/m³.','annual',1998,2024) on conflict (id) do update set name=excluded.name,unit=excluded.unit,source=excluded.source,source_url=excluded.source_url,explainer=excluded.explainer,first_year=excluded.first_year,last_year=excluded.last_year,updated_at=now();